```python
def find_zero(xs: list):
    if len(xs) % 2 != 0:
        raise ValueError("List must have an even number of coefficients.")

    def f(x):
        return poly(xs, x)

    def f_prime(x):
        return sum([i * coeff * math.pow(x, i - 1) for i, coeff in enumerate(xs) if i > 0])

    x0 = 0  # initial guess
    for _ in range(100):  # iterate to find root
        x0 -= f(x0) / f_prime(x0)

    return x0
```

```python
def find_zero(xs: list):
    if len(xs) % 2 != 0:
        raise ValueError("Coefficient list must have an even number of coefficients.")

    def f(x):
        return poly(xs, x)

    def f_prime(x):
        return sum([i * coeff * math.pow(x, i - 1) for i, coeff in enumerate(xs) if i > 0])

    x0 = 0.0
    for _ in range(100):  # Iterate to find the root
        x1 = x0 - f(x0) / f_prime(x0)
        if abs(x1 - x0) < 1e-7:
            return x1
        x0 = x1

    return x0
```

```python
def find_zero(xs: list):
    if len(xs) % 2 != 0:
        raise ValueError("Coefficient list must have an even number of elements.")

    def derivative_poly(xs, x):
        return sum([i * coeff * math.pow(x, i - 1) for i, coeff in enumerate(xs) if i > 0])

    x0 = 0.0  # Initial guess
    for _ in range(100):  # Maximum iterations
        fx = poly(xs, x0)
        dfx = derivative_poly(xs, x0)
        if dfx == 0:
            break
        x1 = x0 - fx / dfx
        if abs(x1 - x0) < 1e-7:
            return x1
        x0 = x1
    return x0
```

```python
def find_zero(xs: list):
    from scipy.optimize import fsolve

    def func(x):
        return poly(xs, x)

    initial_guess = 0
    zero = fsolve(func, initial_guess)[0]
    return zero
```

```python
def fizz_buzz(n: int):
    count = 0
    for i in range(n):
        if (i % 11 == 0 or i % 13 == 0) and '7' in str(i):
            count += str(i).count('7')
    return count
```

