```python
def triples_sum_to_zero(l: list):
    l = list(set(l))  # Remove duplicates
    n = len(l)
    for i in range(n):
        s = set()
        for j in range(i + 1, n):
            target = -(l[i] + l[j])
            if target in s:
                return True
            s.add(l[j])
    return False
```

